    def anv(epost, namn, roller, person=None):
        u = Anvandare(epost=epost, namn=namn, losenord_hash=_hash("demo1234"), person=person)
        db.add(u); db.flush()
        for r, avd, *rest in roller:
            db.add(AnvandarRoll(anvandare=u, roll=r, avdelning=avd, amnesomrade=rest[0] if rest else None))
        return u

